"""Benchmark Greek backends (loop / numpy / cuda) and generate a Markdown report.

The report is generated by this script — never hand-edited — so the numbers in
`docs/benchmarks/greek_backend_benchmark.md` always trace back to a real run on a
recorded machine. Satisfies issue 021 acceptance criterion:
"Benchmark document is generated by script, not manual copy-paste."

What it records:
  - Hardware context (OS, CPU, NumPy/SciPy/CuPy versions, GPU name + VRAM)
  - Per-backend wall-clock (best-of-N) across a sweep of row counts
  - CUDA host<->device transfer time, measured separately from compute
  - Breakeven row count where CUDA first beats NumPy

Usage:
    python tools/benchmark_greeks.py                      # default sweep, writes MD
    python tools/benchmark_greeks.py --rows 1000 100000 5000000
    python tools/benchmark_greeks.py --repeat 7 --output docs/benchmarks/greek_backend_benchmark.md
    python tools/benchmark_greeks.py --json out.json      # also dump raw timings
    python tools/benchmark_greeks.py --no-cuda            # CPU-only sweep

Notes:
  - `loop` is O(rows) in Python and is capped (--loop-max-rows, default 100k);
    larger sizes skip the loop backend so the run stays bounded.
  - CUDA timings include a warmup pass (kernel/JIT/memory-pool startup) that is
    excluded from the measured best-of-N.
"""

from __future__ import annotations

import argparse
import json
import platform
import sys
import time
from datetime import datetime, timezone
from pathlib import Path

import numpy as np

# Repo root on path so `import core.greeks` works when run from anywhere.
_REPO_ROOT = Path(__file__).resolve().parents[1]
if str(_REPO_ROOT) not in sys.path:
    sys.path.insert(0, str(_REPO_ROOT))

from core.greeks import batch_greeks, _cupy_available, _cuda_device_count  # noqa: E402

_DEFAULT_ROWS = [1_000, 10_000, 100_000, 1_000_000, 5_000_000]
_DEFAULT_REPEAT = 5
_DEFAULT_LOOP_MAX = 100_000
_DEFAULT_OUTPUT = "docs/benchmarks/greek_backend_benchmark.md"
_MODEL = "black76"


# ── Inputs ────────────────────────────────────────────────────────────────────

def _make_inputs(n: int, seed: int = 7) -> dict:
    """Deterministic, all-valid option rows (so every backend computes the same set)."""
    rng = np.random.default_rng(seed)
    F = rng.uniform(50.0, 150.0, n)
    K = F * rng.uniform(0.8, 1.2, n)
    T = rng.uniform(0.05, 2.0, n)
    r = rng.uniform(0.0, 0.06, n)
    sigma = rng.uniform(0.1, 0.8, n)
    right = np.where(rng.random(n) < 0.5, "C", "P")
    return {"S_or_F": F, "K": K, "T": T, "r": r, "sigma": sigma, "right": right}


# ── Timing ──────────────────────────────────────────────────────────────────--

def _time_best_of(fn, repeat: int) -> float:
    """Return the minimum wall-clock (seconds) over `repeat` calls. Min, not mean,
    rejects scheduler/GC noise — the floor is the closest estimate of real cost."""
    best = float("inf")
    for _ in range(repeat):
        t0 = time.perf_counter()
        fn()
        dt = time.perf_counter() - t0
        if dt < best:
            best = dt
    return best


def _bench_backend(backend: str, inputs: dict, repeat: int) -> float:
    def run():
        batch_greeks(_MODEL, **inputs, backend=backend)
    # Warmup (excluded): pays one-time import / kernel / memory-pool cost.
    run()
    return _time_best_of(run, repeat)


def _bench_cuda_transfer(inputs: dict, repeat: int) -> float | None:
    """Measure pure host->device->host transfer (no Greek math) for the valid rows."""
    try:
        import cupy as cp
    except Exception:
        return None
    n = len(inputs["S_or_F"])
    arrs = [np.asarray(inputs[k], dtype="float64") for k in ("S_or_F", "K", "T", "r", "sigma")]

    def run():
        gpu = [cp.asarray(a) for a in arrs]
        _ = [cp.asnumpy(g) for g in gpu]
        del gpu
    run()  # warmup
    return _time_best_of(run, repeat)


# ── Hardware context ────────────────────────────────────────────────────────--

def _gpu_info() -> dict | None:
    try:
        import cupy as cp
        if cp.cuda.runtime.getDeviceCount() < 1:
            return None
        props = cp.cuda.runtime.getDeviceProperties(0)
        name = props["name"]
        name = name.decode() if isinstance(name, bytes) else str(name)
        free, total = cp.cuda.runtime.memGetInfo()
        return {
            "name": name,
            "vram_total_gb": round(total / 1024**3, 2),
            "vram_free_gb": round(free / 1024**3, 2),
            "cupy_version": cp.__version__,
            "cuda_runtime": cp.cuda.runtime.runtimeGetVersion(),
        }
    except Exception:
        return None


def _hardware_context() -> dict:
    import scipy
    ctx = {
        "timestamp_utc": datetime.now(timezone.utc).strftime("%Y-%m-%d %H:%M:%S UTC"),
        "os": f"{platform.system()} {platform.release()}",
        "machine": platform.machine(),
        "cpu": platform.processor() or "unknown",
        "python": platform.python_version(),
        "numpy": np.__version__,
        "scipy": scipy.__version__,
        "gpu": _gpu_info(),
    }
    return ctx


# ── Benchmark sweep ───────────────────────────────────────────────────────────

def run_sweep(rows: list[int], repeat: int, loop_max: int, use_cuda: bool) -> dict:
    cuda_ok = use_cuda and _cupy_available()
    results = []
    for n in rows:
        inputs = _make_inputs(n)
        row = {"rows": n}

        if n <= loop_max:
            row["loop"] = _bench_backend("loop", inputs, repeat)
        else:
            row["loop"] = None  # skipped: too slow

        row["numpy"] = _bench_backend("numpy", inputs, repeat)

        if cuda_ok:
            row["cuda"] = _bench_backend("cuda", inputs, repeat)
            row["cuda_transfer"] = _bench_cuda_transfer(inputs, repeat)
        else:
            row["cuda"] = None
            row["cuda_transfer"] = None

        results.append(row)
        _print_progress(row)

    breakeven = _compute_breakeven(results) if cuda_ok else None
    return {
        "model": _MODEL,
        "repeat": repeat,
        "loop_max_rows": loop_max,
        "cuda_enabled": cuda_ok,
        "hardware": _hardware_context(),
        "results": results,
        "cuda_breakeven_rows": breakeven,
    }


def _print_progress(row: dict) -> None:
    def fmt(v):
        return f"{v*1e3:9.3f}ms" if isinstance(v, (int, float)) else "       — "
    print(
        f"rows={row['rows']:>9,}  "
        f"loop={fmt(row['loop'])}  numpy={fmt(row['numpy'])}  cuda={fmt(row['cuda'])}",
        flush=True,
    )


def _compute_breakeven(results: list[dict]) -> int | None:
    """Smallest row count where CUDA wall-clock first drops below NumPy."""
    for row in results:
        if row.get("cuda") is not None and row.get("numpy") is not None:
            if row["cuda"] < row["numpy"]:
                return row["rows"]
    return None


# ── Report ────────────────────────────────────────────────────────────────────

def _ms(v) -> str:
    return f"{v*1e3:.3f}" if isinstance(v, (int, float)) else "—"


def _speedup(base, other) -> str:
    if isinstance(base, (int, float)) and isinstance(other, (int, float)) and other > 0:
        return f"{base/other:.1f}×"
    return "—"


def render_markdown(data: dict) -> str:
    hw = data["hardware"]
    gpu = hw["gpu"]
    lines: list[str] = []

    lines.append("# Greek Backend Benchmark")
    lines.append("")
    lines.append(
        "> Generated by `tools/benchmark_greeks.py`. Do not edit by hand — "
        "re-run the script to refresh."
    )
    lines.append("")
    lines.append(f"- **Generated:** {hw['timestamp_utc']}")
    lines.append(f"- **Model:** `{data['model']}`  ·  **Best-of:** {data['repeat']} runs  ·  "
                 f"**loop cap:** {data['loop_max_rows']:,} rows")
    lines.append("")

    # Hardware
    lines.append("## Hardware Context")
    lines.append("")
    lines.append("| Field | Value |")
    lines.append("|-------|-------|")
    lines.append(f"| OS | {hw['os']} ({hw['machine']}) |")
    lines.append(f"| CPU | {hw['cpu']} |")
    lines.append(f"| Python | {hw['python']} |")
    lines.append(f"| NumPy | {hw['numpy']} |")
    lines.append(f"| SciPy | {hw['scipy']} |")
    if gpu:
        lines.append(f"| GPU | {gpu['name']} ({gpu['vram_total_gb']} GB VRAM) |")
        lines.append(f"| CuPy | {gpu['cupy_version']} (CUDA runtime {gpu['cuda_runtime']}) |")
    else:
        lines.append("| GPU | none detected (CUDA columns omitted) |")
    lines.append("")

    # Timings
    lines.append("## Wall-Clock by Backend")
    lines.append("")
    if data["cuda_enabled"]:
        lines.append("| Rows | loop (ms) | numpy (ms) | cuda (ms) | cuda xfer (ms) | numpy vs loop | cuda vs numpy |")
        lines.append("|-----:|----------:|-----------:|----------:|---------------:|--------------:|--------------:|")
        for r in data["results"]:
            lines.append(
                f"| {r['rows']:,} | {_ms(r['loop'])} | {_ms(r['numpy'])} | {_ms(r['cuda'])} | "
                f"{_ms(r['cuda_transfer'])} | {_speedup(r['loop'], r['numpy'])} | "
                f"{_speedup(r['numpy'], r['cuda'])} |"
            )
    else:
        lines.append("| Rows | loop (ms) | numpy (ms) | numpy vs loop |")
        lines.append("|-----:|----------:|-----------:|--------------:|")
        for r in data["results"]:
            lines.append(
                f"| {r['rows']:,} | {_ms(r['loop'])} | {_ms(r['numpy'])} | "
                f"{_speedup(r['loop'], r['numpy'])} |"
            )
    lines.append("")

    # Breakeven + guidance
    lines.append("## Breakeven & Guidance")
    lines.append("")
    if not data["cuda_enabled"]:
        lines.append("- CUDA not benchmarked (no GPU / CuPy, or `--no-cuda`). "
                     "`backend=\"numpy\"` is the production default.")
    elif data["cuda_breakeven_rows"] is None:
        lines.append("- **CUDA never beat NumPy** in this sweep — NumPy won at every measured size. "
                     "Keep `backend=\"numpy\"`; raise `greeks_cuda_min_rows` above the largest size tested "
                     "or skip CUDA entirely on this hardware.")
    else:
        be = data["cuda_breakeven_rows"]
        lines.append(f"- **CUDA breakeven ≈ {be:,} rows** — CUDA first beats NumPy at/above this size.")
        lines.append(f"- Suggested `greeks_cuda_min_rows`: **{be:,}** (set `backend=\"auto\"` to switch automatically).")
        lines.append("- Below breakeven, host<->device transfer dominates; NumPy wins. Above it, GPU compute amortizes the copy.")
    lines.append("")
    lines.append("> `auto` selects CUDA only when CuPy + a device exist **and** "
                 "`n_rows >= greeks_cuda_min_rows`; otherwise it falls back to NumPy. "
                 "Correctness parity (cuda vs numpy) is enforced by "
                 "`tests/test_core/test_greeks.py::TestBatchGreeksLevel3`.")
    lines.append("")
    return "\n".join(lines)


# ── CLI ─────────────────────────────────────────────────────────────────────--

def main(argv=None) -> int:
    p = argparse.ArgumentParser(description="Benchmark Greek backends and generate a Markdown report.")
    p.add_argument("--rows", type=int, nargs="+", default=_DEFAULT_ROWS,
                   help=f"Row counts to sweep (default: {_DEFAULT_ROWS})")
    p.add_argument("--repeat", type=int, default=_DEFAULT_REPEAT,
                   help=f"Best-of-N timing runs (default: {_DEFAULT_REPEAT})")
    p.add_argument("--loop-max-rows", type=int, default=_DEFAULT_LOOP_MAX,
                   help=f"Skip the loop backend above this size (default: {_DEFAULT_LOOP_MAX:,})")
    p.add_argument("--no-cuda", action="store_true", help="Skip the CUDA backend even if a GPU is present.")
    p.add_argument("--output", default=_DEFAULT_OUTPUT,
                   help=f"Markdown report path (default: {_DEFAULT_OUTPUT})")
    p.add_argument("--json", default=None, help="Optional path to also dump raw timings as JSON.")
    args = p.parse_args(argv)

    if not args.no_cuda and not _cupy_available():
        print(f"[info] No CUDA device detected ({_cuda_device_count()} devices) — running CPU-only sweep.")

    print(f"[bench] model={_MODEL} rows={args.rows} repeat={args.repeat}")
    data = run_sweep(args.rows, args.repeat, args.loop_max_rows, use_cuda=not args.no_cuda)

    md = render_markdown(data)
    out_path = Path(args.output)
    out_path.parent.mkdir(parents=True, exist_ok=True)
    out_path.write_text(md, encoding="utf-8")
    print(f"[bench] report written to {out_path}")

    if args.json:
        json_path = Path(args.json)
        json_path.parent.mkdir(parents=True, exist_ok=True)
        json_path.write_text(json.dumps(data, indent=2), encoding="utf-8")
        print(f"[bench] raw timings written to {json_path}")

    return 0


if __name__ == "__main__":
    sys.exit(main())
